/**
 * @fileoverview Textarea component — modular entry point.
 * @module module/Textarea
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS, CLS } from './constants.js';
import { setupDOM } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';

const Textarea = class {
    #root   = null;
    #destroyed = false;
    #config = {};
    #els    = {};
    #eventAC     = new AbortController();

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Textarea: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#els = setupDOM(root, this.#config);
        this.#init();
    }

    #init() {
        const sig = { signal: this.#eventAC.signal };
        const field = this.#els.field;

        field.addEventListener('focus', () => {
            this.#root.addClass(CLS.FOCUSED);
            this.#config.onFocus?.();
        }, sig);

        field.addEventListener('blur', () => {
            this.#root.removeClass(CLS.FOCUSED);
            this.#config.onBlur?.();
        }, sig);

        field.addEventListener('input', () => {
            this.#config.onInput?.(field.value);
            emitEvent(this.#root[0], 'input', { value: field.value });
        }, sig);

        field.addEventListener('change', () => {
            this.#config.onChange?.(field.value);
            emitEvent(this.#root[0], 'change', { value: field.value });
        }, sig);
    }

    /* ---- Public API ---- */
    get value() { return this.#els.field.value; }
    set value(v) {
        this.#els.field.value = v;
        emitEvent(this.#root[0], 'change', { value: v });
    }

    get element() { return this.#root[0]; }
    get fieldElement() { return this.#els.field; }

    focus() { this.#els.field.focus(); }
    blur() { this.#els.field.blur(); }

    clear() { this.value = ''; }

    setDisabled(state) {
        this.#els.field.disabled = state;
        state ? this.#root.addClass(CLS.DISABLED) : this.#root.removeClass(CLS.DISABLED);
        this.#root[0].setAttribute('aria-disabled', String(!!state));
    }

    setInvalid(state, message) {
        state ? this.#root.addClass(CLS.INVALID) : this.#root.removeClass(CLS.INVALID);
        this.#root[0][state ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    getControl() {
        const self = this;
        return {
            get value()       { return self.value; },
            set value(v)      { self.value = v; },
            get disabled()    { return self.#els.field.disabled; },
            set disabled(v)   { self.setDisabled(v); },
            get readonly()    { return self.#els.field.readOnly; },
            set readonly(v)   { self.#els.field.readOnly = !!v; self.#root.toggleClass(CLS.READONLY, !!v); self.#root[0].setAttribute('aria-readonly', String(!!v)); },
            get required()    { return self.#els.field.required; },
            set required(v)   { self.#els.field.required = !!v; self.#root[0].setAttribute('aria-required', String(!!v)); },
            get placeholder() { return self.#els.field.placeholder; },
            set placeholder(v){ self.#els.field.placeholder = v ?? ''; },
            get rows()        { return self.#els.field.rows; },
            set rows(v)       { self.#els.field.rows = v; },
            get maxlength()   { return self.#els.field.maxLength; },
            set maxlength(v)  { self.#els.field.maxLength = v; },
            get name()        { return self.#els.field.name; },
            set name(v)       { self.#els.field.name = v ?? ''; },
            setDisabled:  (v) => self.setDisabled(v),
            setInvalid:   (v) => self.setInvalid(v),
            checkValidity:     () => self.#els.field.checkValidity(),
            reportValidity:    () => self.#els.field.reportValidity(),
            setCustomValidity: (m) => { self.#els.field.setCustomValidity(m || ''); self.setInvalid(!!m, m); },
            get label()       { return self.#root[0].getAttribute('aria-label'); },
            set label(v)      { v ? self.#root[0].setAttribute('aria-label', v) : self.#root[0].removeAttribute('aria-label'); },
            get labelledby()  { return self.#root[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#root[0].setAttribute('aria-labelledby', v) : self.#root[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#root[0].getAttribute('aria-describedby'); },
            set describedby(v){ v ? self.#root[0].setAttribute('aria-describedby', v) : self.#root[0].removeAttribute('aria-describedby'); },
            focus:        () => self.focus(),
            blur:         () => self.blur(),
            clear:        () => self.clear(),
            destroy:      () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
    }
};

export default Textarea;
