/**
 * @fileoverview Textarea view — DOM setup.
 * @module module/Textarea/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root, config) {
    const el = root[0];
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    // Override potential legacy SASS display
    el.style.display = 'flex';

    // Label
    let labelEl = null;
    if (config.label) {
        const $label = PART.LABEL.create();
        $label.text(config.label);
        root.append($label);
        labelEl = $label[0];
    }

    // Description
    let descEl = null;
    if (config.description) {
        const $desc = PART.DESCRIPTION.create();
        $desc.addClass(CLS.DESCRIPTION).text(config.description);
        root.append($desc);
        descEl = $desc[0];
    }

    // Wrapper
    const $wrapper = PART.WRAPPER.create();
    root.append($wrapper);

    // Field (textarea element)
    const $field = PART.FIELD.create();
    const field = $field[0];
    if (config.placeholder) field.placeholder = config.placeholder;
    if (config.value) field.value = config.value;
    if (config.rows) field.rows = config.rows;
    if (config.maxlength) field.maxLength = config.maxlength;
    if (config.name) field.name = config.name;
    if (config.required) field.required = true;
    if (config.disabled) { field.disabled = true; root.addClass(CLS.DISABLED); }
    if (config.readonly) { field.readOnly = true; root.addClass(CLS.READONLY); }
    $wrapper.append(field);

    // Connect label
    if (labelEl) {
        const id = `ta-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
        field.id = id;
        labelEl.htmlFor = id;
    }

    // Hint
    let hintEl = null;
    if (config.hint) {
        const $hint = PART.HINT.create();
        $hint.text(config.hint);
        root.append($hint);
        hintEl = $hint[0];
    }

    return { wrapper: $wrapper[0], field, labelEl, descEl, hintEl };
}
